INSERT INTO resenha_diaria (tipo_ato, numero_ato, ementa, url, data_publicacao, data_dou) VALUES
('Decreto', 'Decreto nº 12.918, de 31.3.2026', 'Altera o Decreto nº 12.043, de 5 de junho de 2024, que cria a Assessoria Extraordinária para a COP30, aprova o seu Quadro Demonstrativo dos Cargos em Comissão e remaneja, em caráter temporário, cargos em comissão.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/Decreto/D12918.htm', '1º de abril de 2026', '2026-04-01'),
('Lei', 'Lei nº 15.371, de 31.3.2026', 'Dispõe sobre a licença-paternidade; institui o salário-paternidade no âmbito da Previdência Social; e altera a Consolidação das Leis do Trabalho, aprovada pelo Decreto-Lei nº 5.452, de 1º de maio de 1943, e as Leis nºs 8.212, de 24 de julho de 1991 (Lei Orgânica da Seguridade Social), 8.213, de 24 de julho de 1991, e 11.770, de 9 de setembro de 2008.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/Lei/L15371.htm', '1º de abril de 2026', '2026-04-01'),
('Lei', 'Lei nº 15.370, de 31.3.2026', 'Institui o Selo de Engenharia ou Arquitetura Solidária, destinado às empresas e aos profissionais de engenharia, arquitetura ou ramo da construção civil que executarem ou financiarem projetos para atendimento de comunidades carentes, originárias ou tradicionais, de mutuários e de proprietários de imóveis, nos termos que especifica.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/Lei/L15370.htm', '1º de abril de 2026', '2026-04-01'),
('Lei', 'Lei nº 15.369, de 31.3.2026', 'Altera a Lei nº 9.394, de 20 de dezembro de 1996 (Lei de Diretrizes e Bases da Educação Nacional), para definir a extensão da oferta de educação infantil em creches e pré-escolas pelos Municípios às zonas urbanas e rurais.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/Lei/L15369.htm', '1º de abril de 2026', '2026-04-01'),
('Decreto', 'Decreto nº 12.917, de 31.3.2026', 'Altera o Decreto nº 5.493, de 18 de julho de 2005, que regulamenta o disposto na Lei nº 11.096, de 13 de janeiro de 2005, que institui o Programa Universidade para Todos.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/Decreto/D12917.htm', '1º de abril de 2026', '2026-04-01')
